import React from 'react'
import XIcon from '@mui/icons-material/X';
import SiderbarOption from './SiderbarOption';

function Sidebar() {
  return (
    <div className='sidebar'>
        {/* Icon */}
            <XIcon className='sidebar__xIcon'/>
        {/* Sidebar Option */}
            <SiderbarOption/>
        {/* Tweet Button */}
    </div>
  )
}

export default Sidebar;
